public void init()
{

    next init();

    if (curext() == "O014")
    {
        ETG_SalesAgreementHeader_ds.object(fieldNum(ETG_SalesAgreementHeader, SellerBank)).mandatory(true);

    }
    else
    {
        ETG_SalesAgreementHeader_ds.object(fieldNum(ETG_SalesAgreementHeader, SellerBank)).mandatory(false);

    }
    // added code by Ravi to restrict ACF trading details - 26/08 - Start

    if (curext() == "O001")
    {
        ACFTradingDetails.visible(true);

    }
    else
    {
        ACFTradingDetails.visible(false);

    }
    // added code by Ravi to restrict ACF trading details - 26/08 - End



}
